import UIKit

class PasswordResetHandler {
    static func handleUniversalLink(_ url: URL) {
        guard let queryItems = URLComponents(url: url, resolvingAgainstBaseURL: false)?.queryItems else { return }
        
        for item in queryItems {
            if item.name == "token" {
                if let token = item.value {
                    navigateToPasswordResetScreen(withToken: token)
                }
                break
            }
        }
    }
    
